from flask import Flask, send_from_directory, abort
import os

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'txt', 'pdf', 'png', 'jpg', 'jpeg', 'gif'}

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/uploads/<path:filename>', methods=['GET'])
def serve_file(filename):
    # Legacy support for older file naming conventions
    legacy_file = filename.replace('old_prefix_', 'new_prefix_')  # Adjust accordingly
    try:
        if allowed_file(legacy_file) and os.path.isfile(os.path.join(app.config['UPLOAD_FOLDER'], legacy_file)):
            return send_from_directory(app.config['UPLOAD_FOLDER'], legacy_file)
        elif allowed_file(filename) and os.path.isfile(os.path.join(app.config['UPLOAD_FOLDER'], filename)):
            return send_from_directory(app.config['UPLOAD_FOLDER'], filename)
        else:
            abort(404)
    except Exception as e:
        abort(400)

if __name__ == '__main__':
    app.run(debug=True)